mapper.select:
# FORMAT(g.initial_price, 0) 格式化价格，第二个参数为保留小数位数
# case：
#       若销量的字符长度 <= 4 时，不保留小数，       < 表示小于
#       若长度 > 4，则去除掉最后四个字符串（MID 的第二个参数为起始位置，从 1 开始，第三个参数为要截取的字符个数，省略则表示取到末尾），保留剩余的字符串并和 '万+' 拼接
# end：结束 case
select g.id, g.title, g.code, FORMAT(g.initial_price, 0) as initialPrice, FORMAT(g.current_price, 0) as currentPrice,
case
when LENGTH(g.sales_volume) <=4 then FORMAT(g.sales_volume, 0)
else CONCAT(FORMAT(MID(g.sales_volume, 1, LENGTH(g.sales_volume) - 4), 0), '万+')
end as salesVolume,
r.name as ruleName, g.type, g.status, g.part_id as partId, (g.checkup IS NOT NULL ) as hasCheckup
from tb_goods g left join tb_rule r on g.rule_id = r.id


        and g.title like concat('%', #{request.keyword}, '%')


        and g.code like concat('%', #{request.code}, '%')


        and g.type = #{request.type}


        and g.status = #{request.status}


        and g.part_id = #{request.partId}


limit #{start}, #{request.length}

SELECT COUNT(*)
FROM tb_goods


        AND title LIKE CONCAT("%",#{keyword},"%")


        AND type = #{type}


        AND part_id = #{partId}


        AND status = #{status}

